    $header = rtrim(strtr(base64_encode((string) json_encode(['kid' => 'test-kid'])), '+/', '-_'), '=');
    $body = rtrim(strtr(base64_encode((string) json_encode(['server_id' => 'server-123'])), '+/', '-_'), '=');
    $token = $header . '.' . $body . '.sig';

    $request = $this->createRequest('POST', [], 'Bearer ' . $token);
    $response = $controller->allocate($request, ['id' => 'server-123']);

    $this->assertSame(501, $response->statusCode);
    $body = (string) $response->body;
    $this->assertStringContainsString('NOT_IMPLEMENTED', $body);
    $this->assertStringContainsString('tls.acme_not_implemented', $body);
    $this->assertStringContainsString('docs/hub-admin/tls.md', $body);
}

